  "permissions": {
    "allow": [
      "Bash(wails *)",
      "Bash(go *)",
      "Bash(cd frontend && npm *)",
      "Bash(cd frontend && npx *)",
      "Edit(internal/**)",
      "Edit(frontend/src/**)",
      "Edit(app.go)",
      "Edit(main.go)",
      "Bash(gh pr *)",
      "Bash(gh api *)",
      "Bash(git *)",
      "Bash(gh label list)",
      "Bash(gh label create phase-2 --color 1D76DB --description \"Phase 2: 住所録 CRUD\")",
